        dbPath := os.Getenv("DB_PATH")
        if dbPath == "" {
                dbPath = "/opt/jobqueue/jobs.db"
        }

        db, err := sql.Open("sqlite3", dbPath+"?_journal_mode=WAL")
        if err != nil {
                return nil, fmt.Errorf("open: %w", err)
        }
        db.SetMaxOpenConns(1)

        if _, err := db.Exec(schema); err != nil {
